/// </summary>
[ExtensionOf(tableStr(ITMStatusTable))]
internal final class ETGITMStatusTable_Table_Extension
{
}

Method.Source:
public static ITMStatusId firstStatusOutETG(ITMCostArea _costArea)
{
    return (select firstOnly ShipStatusId from ITMStatusTable
                where ITMStatusTable.ShipCostArea == _costArea
                    && ITMStatusTable.ShipStatusIdParent == ITMLibrary::Blank).ShipStatusId;
}
